let current = {"name":"TestName","file":"TestFile.html","gamelib":0}
function opengame(gamelib,name,file) {
    document.getElementById("f").innerText = name;
    document.getElementById("g").innerText = ["230 game library [no names]","599 game library [Reese's Puffs]","1920 game library [Refridgerator]","630 game library"][gamelib];
    current.name = name;
    current.file = file;
    current.gamelib = gamelib;
    document.getElementById("popup").style.display = "initial";
}
async function dl() {
    try {
        const response = await fetch("https://cdn.jsdelivr.net/gh/crshqd/fukkmmii@"+current.gamelib+"/"+current.file);
        if (!response.ok) alert('Error: Network response was not ok');
        const blob = await response.blob();
        const blobUrl = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = blobUrl;
        link.download = "dlpack-download.html";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(blobUrl);
        
    } catch (error) {
        alert("Error: Download failed:", error);
    }
}
